import json, pandas as pd

biz = pd.DataFrame(var_call_XopDAaXkaco6Ep15PNhnDFRB)
rev = pd.DataFrame(var_call_jA0NJfgg2GDvtKONbgtYXBL1)

# parse hours which are stored as JSON strings
biz['hours_parsed'] = biz['hours'].apply(lambda s: json.loads(s) if isinstance(s,str) else s)

weekdays = {'Monday','Tuesday','Wednesday','Thursday','Friday'}

def closes_after_6pm(hours_list):
    # hours_list: list of [day, hours_str]
    for day, hrs in hours_list:
        if day not in weekdays:
            continue
        if not isinstance(hrs,str):
            continue
        if 'Closed' in hrs:
            continue
        if '24 hours' in hrs:
            return True
        # handle formats like '11AM–9:30PM' or '6:30AM–6PM'
        if '–' in hrs:
            end = hrs.split('–')[-1].strip()
        elif '-' in hrs:
            end = hrs.split('-')[-1].strip()
        else:
            continue
        # normalize like '6PM' '9:30PM'
        # convert to minutes since midnight
        import re
        m = re.match(r'^(\d{1,2})(?::(\d{2}))?\s*(AM|PM)$', end.replace(' ',''))
        if not m:
            continue
        h = int(m.group(1))
        minute = int(m.group(2) or 0)
        ampm = m.group(3)
        if ampm == 'AM':
            h24 = 0 if h==12 else h
        else:
            h24 = 12 if h==12 else h+12
        mins = h24*60 + minute
        if mins > 18*60:
            return True
    return False

biz['open_after_6_weekday'] = biz['hours_parsed'].apply(closes_after_6pm)

out = biz.merge(rev, on='gmap_id', how='left')
out['avg_rating'] = out['avg_rating'].astype(float)

out = out[out['open_after_6_weekday']].sort_values(['avg_rating','review_count'], ascending=[False, False]).head(5)

result = out[['name','hours_parsed','avg_rating']].to_dict('records')
print('__RESULT__:')
print(json.dumps(result))

